module top_module(
  input clk,
  input reset,
  output reg [3:0] count
);reg [3:0] cnt_reg;

always @(posedge clk) begin
  if (reset) begin
    cnt_reg <= 4'b0000;
  end
  else begin
    if (cnt_reg == 4'b0111) begin
      cnt_reg <= 4'b0000;
    end
    else begin
      cnt_reg <= cnt_reg + 1;
    end
  end
end

assign count = cnt_reg;

endmodule
